   336→    list->tail = tail->prev;
   337→    list->tail->next = NULL;
   338→    /* Move it as head */
   339→    list->head->prev = tail;
   340→    tail->prev = NULL;
   341→    tail->next = list->head;
   342→    list->head = tail;
   343→}
